export const allQuestions: Question[] = questionBank.filter((question) => question.category !== 'Verdadeiro ou Falso')

export function sanitizeUsedQuestionIds(usedQuestionIds?: string[] | null): string[] {
  return Array.from(
    new Set(
      (usedQuestionIds || []).filter(
        (questionId): questionId is string => typeof questionId === 'string' && questionId.trim().length > 0
      )
    )
  )
}
